/**
 * lib/component-registry.ts
 *
 * The complete component library for Opollo site generation.
 * 8 component types. 20 variants total. This is the complete v1 list.
 * No additions without a milestone decision.
 *
 * Field schemas copied from payloadcms/payload website template blocks (MIT).
 * Render HTML adapted from HyperUI (https://www.hyperui.dev) (MIT).
 *
 * CSS class naming: opollo-{ComponentType} opollo-{ComponentType}--{variant}
 * CSS classes are NEVER generated by the LLM.
 * All render functions use CSS variables, never inline styles or Tailwind.
 */

import type { ComponentRegistry, Fields, RenderTarget } from './types/page-document';

