// ─── FEATURES ────────────────────────────────────────────────────────────────

function featureItems(features: FeatureShape[], extraItemClass = ''): string {
  if (!features.length) return '';
  return features.map(f => `      <li class="opollo-Features__item${extraItemClass}">
        ${checkIcon()}
        <div class="opollo-Features__item-body">
          ${f.title ? `<h3 class="opollo-h3">${esc(f.title)}</h3>` : ''}
          ${f.description ? `<p>${esc(f.description)}</p>` : ''}
        </div>
      </li>`).join('\n');
}

