// ─── TESTIMONIAL ─────────────────────────────────────────────────────────────

function renderTestimonialSingle(props: Record<string, unknown>, _t: RenderTarget): string {
  const id      = esc(props.id);
  const heading = esc(props.heading);
  // Single variant: use first item from embedded array, or resolved single testimonial
  const ts      = asArray<TestimonialShape>(props.testimonials);
  const t       = ts[0] ?? (props.testimonial as TestimonialShape | undefined);
  const quote   = esc(t?.quote ?? '');
  const author  = esc(t?.author ?? '');
  const role    = esc(t?.role ?? '');
  const company = esc(t?.company ?? '');
  const byline  = [role, company].filter(Boolean).join(', ');
  return `<section class="opollo-Testimonial opollo-Testimonial--single" data-opollo-id="${id}">
  <div class="opollo-container opollo-section-padding">
    ${heading ? `<h2 class="opollo-h2 opollo-Testimonial__heading">${heading}</h2>` : ''}
    <figure class="opollo-Testimonial__figure">
      <blockquote class="opollo-Testimonial__quote"><p>${quote}</p></blockquote>
      <figcaption class="opollo-Testimonial__caption">
        <cite class="opollo-Testimonial__author">${author}</cite>${byline ? `\n        <span class="opollo-Testimonial__role">${byline}</span>` : ''}
      </figcaption>
    </figure>
  </div>
</section>`;
}

function renderTestimonialGrid(props: Record<string, unknown>, _t: RenderTarget): string {
  const id           = esc(props.id);
  const heading      = esc(props.heading);
  const testimonials = asArray<TestimonialShape>(props.testimonials);
  const items = testimonials.map(t => {
    const quote   = esc(t.quote ?? '');
    const author  = esc(t.author ?? '');
    const role    = esc(t.role ?? '');
    const company = esc(t.company ?? '');
    const byline  = [role, company].filter(Boolean).join(', ');
    return `      <li class="opollo-Testimonial__card">
        <figure>
          <blockquote class="opollo-Testimonial__card-quote"><p>${quote}</p></blockquote>
          <figcaption class="opollo-Testimonial__card-caption">
            <cite class="opollo-Testimonial__author">${author}</cite>${byline ? `\n            <span class="opollo-Testimonial__role">${byline}</span>` : ''}
          </figcaption>
        </figure>
      </li>`;
  }).join('\n');
  return `<section class="opollo-Testimonial opollo-Testimonial--grid" data-opollo-id="${id}">
  <div class="opollo-container opollo-section-padding">
    ${heading ? `<h2 class="opollo-h2 opollo-Testimonial__heading">${heading}</h2>` : ''}
    <ul class="opollo-Testimonial__grid" role="list">
${items}
    </ul>
  </div>
</section>`;
}

