// ─── CONTACT ─────────────────────────────────────────────────────────────────

function contactDetails(email: string, phone: string, address: string): string {
  const items: string[] = [];
  if (email)   items.push(`<li class="opollo-Contact__detail-item"><span class="opollo-Contact__detail-label">Email</span><a href="mailto:${esc(email)}">${esc(email)}</a></li>`);
  if (phone)   items.push(`<li class="opollo-Contact__detail-item"><span class="opollo-Contact__detail-label">Phone</span><a href="tel:${esc(phone)}">${esc(phone)}</a></li>`);
  if (address) items.push(`<li class="opollo-Contact__detail-item"><span class="opollo-Contact__detail-label">Address</span><address class="opollo-Contact__address">${esc(address)}</address></li>`);
  return items.length ? `<ul class="opollo-Contact__details">\n        ${items.join('\n        ')}\n      </ul>` : '';
}

function renderContactForm(props: Record<string, unknown>, _t: RenderTarget): string {
  const id         = esc(props.id);
  const heading    = esc(props.heading);
  const subheading = esc(props.subheading);
  const email      = String(props.email ?? '');
  const phone      = String(props.phone ?? '');
  const address    = String(props.address ?? '');
  const details    = contactDetails(email, phone, address);
  return `<section class="opollo-Contact opollo-Contact--form" data-opollo-id="${id}">
  <div class="opollo-container opollo-section-padding">
    <div class="opollo-Contact__split">
      <div class="opollo-Contact__info">
        ${heading ? `<h2 class="opollo-h2">${heading}</h2>` : ''}
        ${subheading ? `<p class="opollo-lead">${subheading}</p>` : ''}
        ${details}
      </div>
      <div class="opollo-Contact__form-wrap">
        <form class="opollo-Contact__form" method="post" action="#">
          <label class="opollo-Contact__label" for="name-${id}">Name</label>
          <input class="opollo-Contact__input" type="text" id="name-${id}" name="name" required autocomplete="name">
          <label class="opollo-Contact__label" for="email-${id}">Email</label>
          <input class="opollo-Contact__input" type="email" id="email-${id}" name="email" required autocomplete="email">
          <label class="opollo-Contact__label" for="message-${id}">Message</label>
          <textarea class="opollo-Contact__input opollo-Contact__textarea" id="message-${id}" name="message" rows="5" required></textarea>
          <button type="submit" class="opollo-btn opollo-btn--primary opollo-Contact__submit">Send message</button>
        </form>
      </div>
    </div>
  </div>
</section>`;
}

function renderContactDetails(props: Record<string, unknown>, _t: RenderTarget): string {
  const id         = esc(props.id);
  const heading    = esc(props.heading);
  const subheading = esc(props.subheading);
  const email      = String(props.email ?? '');
  const phone      = String(props.phone ?? '');
  const address    = String(props.address ?? '');
  const details    = contactDetails(email, phone, address);
  return `<section class="opollo-Contact opollo-Contact--details" data-opollo-id="${id}">
  <div class="opollo-container opollo-section-padding">
    ${heading ? `<h2 class="opollo-h2">${heading}</h2>` : ''}
    ${subheading ? `<p class="opollo-lead">${subheading}</p>` : ''}
    ${details}
  </div>
</section>`;
}

